function saveTodayAttendance() {
    const records = {};
    let presentCount = 0;
    let lateCount = 0;
    let leaveCount = 0;
    let absentCount = 0;

    const studentIds = ['stu-1', 'stu-2', 'stu-3'];
    let fullyMarked = true;

    studentIds.forEach(id => {
        // Read from active tab table
        const tabTable = document.getElementById('attendance-today-content');
        const actionCell = tabTable ? tabTable.querySelector('#action-' + id) : null;
        if (!actionCell) return;

        const badge = actionCell.querySelector('.status-badge');
        if (!badge) {
            fullyMarked = false;
            return;
        }

        if (badge.classList.contains('present')) {
            records[id] = 'present';
            presentCount++;
        } else if (badge.classList.contains('late')) {
            records[id] = 'late';
            lateCount++;
        } else if (badge.classList.contains('leave')) {
            records[id] = 'leave';
            leaveCount++;
        } else if (badge.classList.contains('absent')) {
            records[id] = 'absent';
            absentCount++;
        }
    });

    if (!fullyMarked) {
        showToast('บันทึกไม่สำเร็จ', 'กรุณาทำการเช็คชื่อนักเรียนให้ครบถ้วนทุกคนก่อนกดบันทึกครับ', 'warning');
        return;
    }

    const history = getAttendanceHistory();

    const dateInput = document.querySelector('#panel-attendance #attendance-date-select');
    const targetDateStr = dateInput ? formatToThaiDate(dateInput.value) : getTodayThaiDate();

    const classVal = document.getElementById('class-select') ? document.getElementById('class-select').value : 'm3';
    const roomVal = document.getElementById('room-select') ? document.getElementById('room-select').value : '1';

    const newEntry = {
        date: targetDateStr,
        class: classVal,
        room: roomVal,
        total: studentIds.length,
        present: presentCount,
        late: lateCount,
        leave: leaveCount,
        absent: absentCount,
        rate: Math.round(((presentCount + lateCount + leaveCount) / studentIds.length) * 100),
        records: records
    };

