function updateAttendanceSummary() {
    const classVal = document.getElementById('summary-class-select').value;
    const roomVal = document.getElementById('summary-room-select').value;

    let present = 0, late = 0, leave = 0, absent = 0, unchecked = 0;
    let total = 0;

    const history = getAttendanceHistory();
    const dateInput = document.querySelector('#panel-attendance #attendance-date-select');
    const targetDateStr = dateInput ? formatToThaiDate(dateInput.value) : getTodayThaiDate();

    // Check if there is saved history for this class and room on the active date
    const entry = history.find(h => h.date === targetDateStr && (h.class || 'm3') === classVal && (h.room || '1') === roomVal);

    if (entry) {
        present = entry.present;
        late = entry.late;
        leave = entry.leave || 0;
        absent = entry.absent;
        total = entry.total;
        unchecked = 0;
    } else {
        // No saved history, fallback to reading DOM if classVal and roomVal are currently selected
        const curClass = document.getElementById('class-select') ? document.getElementById('class-select').value : '';
        const curRoom = document.getElementById('room-select') ? document.getElementById('room-select').value : '';

        if (classVal === curClass && roomVal === curRoom) {
            const studentIds = ['stu-1', 'stu-2', 'stu-3'];
            studentIds.forEach(id => {
                const tabTable = document.getElementById('attendance-today-content');
                const actionCell = tabTable ? tabTable.querySelector('#action-' + id) : null;
                if (actionCell) {
                    const badge = actionCell.querySelector('.status-badge');
                    if (badge) {
                        if (badge.classList.contains('present')) present++;
                        else if (badge.classList.contains('late')) late++;
                        else if (badge.classList.contains('leave')) leave++;
                        else if (badge.classList.contains('absent')) absent++;
                    } else {
                        unchecked++;
                    }
                }
            });
            total = studentIds.length;
        } else {
            // Fallback to deterministic mock statistics
            const baseSize = classVal === 'm1' ? 30 : classVal === 'm2' ? 28 : 25;
            const offset = parseInt(roomVal) * 2;
            total = baseSize - offset;

            present = Math.round(total * 0.85);
            late = Math.round(total * 0.08);
            leave = Math.round(total * 0.04);
            absent = total - present - late - leave;
            unchecked = 0;
        }
    }

    const markedTotal = present + late + leave + absent;

    let presentPct = 0, latePct = 0, leavePct = 0, absentPct = 0, uncheckedPct = 100;
    if (total > 0) {
        presentPct = Math.round((present / total) * 100);
        latePct = Math.round((late / total) * 100);
        leavePct = Math.round((leave / total) * 100);
        absentPct = Math.round((absent / total) * 100);
        uncheckedPct = 100 - (presentPct + latePct + leavePct + absentPct);
    }

    // Update labels
    const pEl = document.getElementById('summary-att-present-count');
    if (pEl) pEl.innerText = `${present} คน`;
    const lEl = document.getElementById('summary-att-late-count');
    if (lEl) lEl.innerText = `${late} คน`;
    const lvEl = document.getElementById('summary-att-leave-count');
    if (lvEl) lvEl.innerText = `${leave} คน`;
    const aEl = document.getElementById('summary-att-absent-count');
    if (aEl) aEl.innerText = `${absent} คน`;

    // Update bar chart segments (no text inside, purely visual)
    const bar = document.getElementById('summary-att-bar');
    if (bar) {
        bar.innerHTML = `
            <div class="attendance-bar-segment segment-present" style="width: ${presentPct}%; display: ${presentPct > 0 ? 'block' : 'none'};"></div>
            <div class="attendance-bar-segment segment-late" style="width: ${latePct}%; display: ${latePct > 0 ? 'block' : 'none'};"></div>
            <div class="attendance-bar-segment segment-leave" style="width: ${leavePct}%; display: ${leavePct > 0 ? 'block' : 'none'};"></div>
            <div class="attendance-bar-segment segment-absent" style="width: ${absentPct}%; display: ${absentPct > 0 ? 'block' : 'none'};"></div>
        `;
    }

    // Sync average attendance statistics grid
    // Find if there's saved history for today/selected date to count into overall average
    let sumRate = 0;
    let dayCount = history.length;

    // Calculate current average
    if (markedTotal === total && total > 0) {
        const currentRate = Math.round(((present + late + leave) / total) * 100);
        const hasSavedToday = history.some(h => h.date === targetDateStr);
        if (hasSavedToday) {
            const tempHistory = history.map(h => h.date === targetDateStr ? { ...h, rate: currentRate } : h);
            sumRate = tempHistory.reduce((acc, h) => acc + h.rate, 0);
        } else {
            sumRate = history.reduce((acc, h) => acc + h.rate, 0) + currentRate;
            dayCount += 1;
        }
    } else {
        sumRate = history.reduce((acc, h) => acc + h.rate, 0);
    }

